CREATE OR REPLACE VIEW `passive-portfolio-lab.passive_portfolio.looker_asset_metrics` AS
WITH
asset_metadata AS (
  SELECT * FROM UNNEST([
    STRUCT('0050.TW' AS ticker, 'Yuanta Taiwan 50 ETF' AS name, 'TW_ETF' AS category, 'Market-Cap' AS subcategory, 1 AS aum_rank, 'approx. TWD 1,661.5B' AS aum_note, 'Tracks the top 50 Taiwan companies by market cap; the core passive investment vehicle for the Taiwan stock market.' AS description),
    STRUCT('0056.TW' AS ticker, 'Yuanta High Dividend ETF' AS name, 'TW_ETF' AS category, 'High Dividend' AS subcategory, 2 AS aum_rank, 'approx. TWD 584.1B' AS aum_note, 'Selects the 30 Taiwan stocks with the highest forecast cash dividend yield; the flagship high-dividend ETF in Taiwan.' AS description),
    STRUCT('00878.TW' AS ticker, 'Cathay Sustainable High Dividend ETF' AS name, 'TW_ETF' AS category, 'High Dividend / ESG' AS subcategory, 3 AS aum_rank, 'approx. TWD 485.4B' AS aum_note, 'Combines ESG screening with a high-dividend strategy; pays quarterly dividends.' AS description),
    STRUCT('00919.TW' AS ticker, 'Group Benefits Taiwan Select High Yield ETF' AS name, 'TW_ETF' AS category, 'High Dividend' AS subcategory, 4 AS aum_rank, 'approx. TWD 451.8B' AS aum_note, 'High-dividend plus multi-factor stock selection; monthly distributions; fast-growing AUM.' AS description),
    STRUCT('006208.TW' AS ticker, 'Fubon Taiwan 50 ETF' AS name, 'TW_ETF' AS category, 'Market-Cap' AS subcategory, 5 AS aum_rank, 'approx. TWD 389.4B' AS aum_note, 'Also tracks the Taiwan 50 index; a competitor to 0050 with a lower expense ratio.' AS description),
