    STRUCT('AGG' AS ticker, 'iShares Core U.S. Aggregate Bond ETF' AS name, 'US_ETF' AS category, 'US Total Bond' AS subcategory, 14 AS aum_rank, 'approx. USD 135.9B' AS aum_note, 'Tracks the Bloomberg US Aggregate Bond Index; highly similar to BND.' AS description),
    STRUCT('IEF' AS ticker, 'iShares 7-10 Year Treasury Bond ETF' AS name, 'US_ETF' AS category, 'Intermediate US Treasury' AS subcategory, 15 AS aum_rank, 'approx. USD 45.0B' AS aum_note, 'Moderate interest-rate sensitivity; commonly used as an equity hedge.' AS description),
    STRUCT('BTC-USD' AS ticker, 'Bitcoin' AS name, 'CRYPTO' AS category, 'Store of Value' AS subcategory, 1 AS aum_rank, 'approx. USD 1,300.0B' AS aum_note, '~58% market dominance; digital gold and the preferred crypto asset for institutional holdings.' AS description),
    STRUCT('ETH-USD' AS ticker, 'Ethereum' AS name, 'CRYPTO' AS category, 'Smart Contract Platform' AS subcategory, 2 AS aum_rank, 'approx. USD 280.0B' AS aum_note, 'Core infrastructure for DeFi, NFTs, and Layer 2; the world\'s second-largest cryptocurrency.' AS description),
    STRUCT('BNB-USD' AS ticker, 'BNB' AS name, 'CRYPTO' AS category, 'Exchange Platform Token' AS subcategory, 3 AS aum_rank, 'approx. USD 85.0B' AS aum_note, 'Native token of the Binance ecosystem and BNB Chain; features a periodic token-burn mechanism.' AS description),
    STRUCT('XRP-USD' AS ticker, 'XRP' AS name, 'CRYPTO' AS category, 'Cross-Border Payments' AS subcategory, 4 AS aum_rank, 'approx. USD 65.0B' AS aum_note, 'Led by Ripple; focused on institutional cross-border settlement with 3–5 second finality.' AS description),
    STRUCT('SOL-USD' AS ticker, 'Solana' AS name, 'CRYPTO' AS category, 'High-Performance L1' AS subcategory, 5 AS aum_rank, 'approx. USD 65.0B' AS aum_note, 'High throughput and low fees; one of the most active chains for DeFi and meme coins.' AS description),
    STRUCT('TRX-USD' AS ticker, 'TRON' AS name, 'CRYPTO' AS category, 'Stablecoin Settlement Chain' AS subcategory, 6 AS aum_rank, 'approx. USD 25.0B' AS aum_note, 'The largest chain for USDT on-chain activity; low-fee stablecoin ecosystem.' AS description),
    STRUCT('DOGE-USD' AS ticker, 'Dogecoin' AS name, 'CRYPTO' AS category, 'Meme Coin' AS subcategory, 7 AS aum_rank, 'approx. USD 25.0B' AS aum_note, 'The most liquid meme coin; PoW consensus mechanism with a strong community following.' AS description),
    STRUCT('ADA-USD' AS ticker, 'Cardano' AS name, 'CRYPTO' AS category, 'Academic L1' AS subcategory, 8 AS aum_rank, 'approx. USD 20.0B' AS aum_note, 'Research-driven development; PoS consensus with regulatory compliance focus and mature governance.' AS description)
  ])
)
SELECT
  m.ticker,
  md.name,
  md.category,
  md.subcategory,
  md.aum_rank,
  md.aum_note,
  md.description,
  CASE WHEN md.category = 'TW_ETF' THEN 'TWD' ELSE 'USD' END AS currency,
  DATE(m.data_start) AS data_start,
  DATE(m.data_end) AS data_end,
  m.cagr,
  m.volatility,
  m.max_drawdown,
  m.sharpe_ratio,
  m.recovery_period_days,
  m.recovery_status,
  m.worst_year,
  m.worst_year_label,
  ROUND(m.cagr * 100, 2) AS cagr_pct,
  ROUND(m.volatility * 100, 2) AS volatility_pct,
  ROUND(m.max_drawdown * 100, 2) AS max_drawdown_pct,
  ROUND(m.worst_year * 100, 2) AS worst_year_pct
FROM `passive-portfolio-lab.passive_portfolio.asset_metrics` AS m
LEFT JOIN asset_metadata AS md USING (ticker);

