    STRUCT('SOL-USD' AS ticker, 'Solana' AS name, 'CRYPTO' AS category, 'High-Performance L1' AS subcategory, 5 AS aum_rank, 'approx. USD 65.0B' AS aum_note, 'High throughput and low fees; one of the most active chains for DeFi and meme coins.' AS description),
    STRUCT('TRX-USD' AS ticker, 'TRON' AS name, 'CRYPTO' AS category, 'Stablecoin Settlement Chain' AS subcategory, 6 AS aum_rank, 'approx. USD 25.0B' AS aum_note, 'The largest chain for USDT on-chain activity; low-fee stablecoin ecosystem.' AS description),
    STRUCT('DOGE-USD' AS ticker, 'Dogecoin' AS name, 'CRYPTO' AS category, 'Meme Coin' AS subcategory, 7 AS aum_rank, 'approx. USD 25.0B' AS aum_note, 'The most liquid meme coin; PoW consensus mechanism with a strong community following.' AS description),
    STRUCT('ADA-USD' AS ticker, 'Cardano' AS name, 'CRYPTO' AS category, 'Academic L1' AS subcategory, 8 AS aum_rank, 'approx. USD 20.0B' AS aum_note, 'Research-driven development; PoS consensus with regulatory compliance focus and mature governance.' AS description)
  ])
),
prices AS (
  SELECT
    DATE(date) AS date,
    ticker,
    SAFE_CAST(close AS FLOAT64) AS close
  FROM `passive-portfolio-lab.passive_portfolio.raw_prices`
  WHERE close IS NOT NULL
),
enriched AS (
  SELECT
    p.date,
    p.ticker,
    md.name,
    md.category,
    md.subcategory,
    CASE WHEN md.category = 'TW_ETF' THEN 'TWD' ELSE 'USD' END AS currency,
    p.close,
    LAG(p.close) OVER (PARTITION BY p.ticker ORDER BY p.date) AS previous_close,
    FIRST_VALUE(p.close) OVER (
      PARTITION BY p.ticker
      ORDER BY p.date
      ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING
    ) AS first_close
  FROM prices AS p
  LEFT JOIN asset_metadata AS md USING (ticker)
)
SELECT
  date,
  ticker,
  name,
  category,
  subcategory,
  currency,
  close,
  SAFE_DIVIDE(close, previous_close) - 1 AS daily_return,
  SAFE_DIVIDE(close, first_close) - 1 AS cumulative_return,
  ROUND((SAFE_DIVIDE(close, previous_close) - 1) * 100, 4) AS daily_return_pct,
  ROUND((SAFE_DIVIDE(close, first_close) - 1) * 100, 2) AS cumulative_return_pct
FROM enriched;

CREATE OR REPLACE VIEW `passive-portfolio-lab.passive_portfolio.looker_annual_returns` AS
WITH yearly AS (
  SELECT
    EXTRACT(YEAR FROM date) AS year,
    ticker,
    name,
    category,
    subcategory,
    currency,
    ARRAY_AGG(close ORDER BY date ASC LIMIT 1)[OFFSET(0)] AS first_close,
    ARRAY_AGG(close ORDER BY date DESC LIMIT 1)[OFFSET(0)] AS last_close
  FROM `passive-portfolio-lab.passive_portfolio.looker_price_history`
  GROUP BY year, ticker, name, category, subcategory, currency
)
SELECT
  year,
  ticker,
  name,
  category,
  subcategory,
  currency,
  SAFE_DIVIDE(last_close, first_close) - 1 AS annual_return,
  ROUND((SAFE_DIVIDE(last_close, first_close) - 1) * 100, 2) AS annual_return_pct
FROM yearly;

CREATE OR REPLACE VIEW `passive-portfolio-lab.passive_portfolio.looker_category_summary` AS
SELECT
  category,
  COUNT(*) AS asset_count,
  AVG(cagr) AS avg_cagr,
  AVG(volatility) AS avg_volatility,
  AVG(max_drawdown) AS avg_max_drawdown,
  AVG(sharpe_ratio) AS avg_sharpe_ratio,
  ROUND(AVG(cagr) * 100, 2) AS avg_cagr_pct,
  ROUND(AVG(volatility) * 100, 2) AS avg_volatility_pct,
  ROUND(AVG(max_drawdown) * 100, 2) AS avg_max_drawdown_pct
FROM `passive-portfolio-lab.passive_portfolio.looker_asset_metrics`
GROUP BY category;
